import{_ as t,o as a,c as i,a3 as s}from"./chunks/framework.LBeL10WQ.js";const m=JSON.parse('{"title":"Logistics & Tech","description":"","frontmatter":{"title":"Logistics & Tech"},"headers":[],"relativePath":"en/faq/logistics-tech.md","filePath":"en/faq/logistics-tech.md"}'),r={name:"en/faq/logistics-tech.md"};function o(l,e,n,d,c,g){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="logistics-print-tech" tabindex="-1">Logistics, Print &amp; Tech <a class="header-anchor" href="#logistics-print-tech" aria-label="Permalink to &quot;Logistics, Print &amp; Tech&quot;">​</a></h1><h2 id="technical-troubleshooting" tabindex="-1">Technical Troubleshooting <a class="header-anchor" href="#technical-troubleshooting" aria-label="Permalink to &quot;Technical Troubleshooting&quot;">​</a></h2><details class="details custom-block"><summary>My QR Code redirects to a 404 page</summary><p><strong>Probable cause:</strong> The destination URL configured in the platform is empty or incorrect.</p><p><strong>Solution:</strong></p><ol><li>Log in to <a href="https://app.getinside.media" target="_blank" rel="noreferrer">app.getinside.media</a>.</li><li>Go to the relevant campaign → <em>Configuration</em> tab.</li><li>Check the <strong>&quot;Redirection URL&quot;</strong> field.</li><li>Save — the update is <strong>instantaneous</strong> (no need to reprint).</li></ol></details><details class="details custom-block"><summary>I can&#39;t boost the Instagram post</summary><p><strong>Cause:</strong> The &quot;Allow partner to boost&quot; box was not checked during publication.</p><p><strong>Solution:</strong></p><ol><li>Go to the Instagram post → 3 dots → Edit.</li><li>Verify that the <strong>&quot;Paid partnership&quot;</strong> label is active.</li><li>Verify that the <strong>&quot;Allow brand partner to boost&quot;</strong> option is active.</li></ol></details><details class="details custom-block"><summary>The image in my newsletter is not displaying</summary><p><strong>Cause:</strong> Hosting or link issue.</p><p>Check:</p><ul><li>Is the image link in <code>https</code>? (Mandatory)</li><li>Is the image hosted on a public server?</li><li>Have you respected the maximum weight (150 KB)?</li></ul><p><em>Test: open the image URL alone in a private browser. If it doesn&#39;t load, the problem is with the hosting.</em></p></details><hr><h2 id="logistics-management" tabindex="-1">Logistics Management <a class="header-anchor" href="#logistics-management" aria-label="Permalink to &quot;Logistics Management&quot;">​</a></h2><details class="details custom-block"><summary>I received the inserts early — can I start?</summary><p>It is imperative to have the advertiser&#39;s green light to broadcast a campaign earlier than planned. This can cause problems if the landing page is not yet active or if the campaign competes with another offer.</p></details><details class="details custom-block"><summary>The flyers arrived damaged</summary><p><strong>Immediate action required (within 24h):</strong></p><ol><li>Take clear photos of the damaged boxes.</li><li>Note specific reservations on the delivery slip (BL).</li><li>Send everything to <code>logistique@getinside.fr</code>.</li></ol><p>Do not distribute the damaged materials.</p></details><details class="details custom-block"><summary>Stock discrepancy — I received more or fewer flyers than expected</summary><p><strong>You received FEWER:</strong> immediately notify the advertiser and getinside via the campaign messaging.</p><p><strong>You received MORE (surplus):</strong> this is normal. This surplus corresponds to the spoilage tolerance regulated by Article 38 of the Code of practices of the graphic industry (UNIIC). See the section below for details.</p></details><hr><h2 id="management-of-print-surplus-spoilage-tolerance" tabindex="-1">Management of Print Surplus (Spoilage Tolerance) <a class="header-anchor" href="#management-of-print-surplus-spoilage-tolerance" aria-label="Permalink to &quot;Management of Print Surplus (Spoilage Tolerance)&quot;">​</a></h2><p>Industrial printing generates inevitable variations between the quantity ordered and the quantity delivered. This is not an error — it is a codified production standard.</p><div class="tip custom-block"><p class="custom-block-title">Article 38 — Code of practices of the graphic industry (UNIIC)</p><p>The buyer is <strong>required to accept</strong> the following delivery discrepancies, which are inherent to manufacturing hazards:</p></div><table tabindex="0"><thead><tr><th style="text-align:left;">Ordered volume (BAT)</th><th style="text-align:left;">Legal tolerance</th></tr></thead><tbody><tr><td style="text-align:left;">≤ 2,000 ex</td><td style="text-align:left;">± 10%</td></tr><tr><td style="text-align:left;">≤ 10,000 ex</td><td style="text-align:left;">± 8%</td></tr><tr><td style="text-align:left;">≤ 20,000 ex</td><td style="text-align:left;">± 6.5%</td></tr><tr><td style="text-align:left;">≤ 25,000 ex</td><td style="text-align:left;">± 5.5%</td></tr><tr><td style="text-align:left;">≤ 35,000 ex</td><td style="text-align:left;">± 4.5%</td></tr><tr><td style="text-align:left;">≤ 50,000 ex</td><td style="text-align:left;">± 3.5%</td></tr><tr><td style="text-align:left;">≤ 100,000 ex</td><td style="text-align:left;">± 2.5%</td></tr><tr><td style="text-align:left;">&gt; 100,000 ex</td><td style="text-align:left;">± 2%</td></tr></tbody></table><p><strong>Procedure for surplus:</strong></p><ol><li>Distribute the surplus if possible (unchanged budget, additional volume = bonus for the advertiser).</li><li>If insertion is impossible (warehouse full, campaign ended), direct to recycling.</li><li>If the advertiser disputes: reference Article 38 UNIIC and your delivery slip.</li></ol><hr><h2 id="transport-damage" tabindex="-1">Transport Damage <a class="header-anchor" href="#transport-damage" aria-label="Permalink to &quot;Transport Damage&quot;">​</a></h2><details class="details custom-block"><summary>I received a few damaged boxes — should I block the campaign?</summary><p>No, unless the damage exceeds 1% of the total volume.</p><p>A <strong>minor damage</strong> (less than 1% of the delivered volume) is considered non-blocking according to the logistics standards of freight transport. In this case:</p><ol><li>Take clear photos of the damaged boxes.</li><li>Note reservations on the delivery slip (BL).</li><li>Isolate the damaged materials.</li><li>Start distribution on the rest of the stock.</li><li>Send the photos to <code>logistique@getinside.fr</code> for an insurance file if necessary.</li></ol><div class="warning custom-block"><p class="custom-block-title">Major damage (&gt; 1% of the volume)</p><p>If the damage exceeds 1% of the volume or if the materials do not comply with the validated proof, <strong>suspend the insertion</strong> and contact <code>logistique@getinside.fr</code> before any distribution.</p></div></details><hr><h2 id="data-gdpr" tabindex="-1">Data &amp; GDPR <a class="header-anchor" href="#data-gdpr" aria-label="Permalink to &quot;Data &amp; GDPR&quot;">​</a></h2><details class="details custom-block"><summary>An advertiser asks for the recipients&#39; addresses — can I provide them?</summary><p><strong>No.</strong> This request is not allowed, even if the advertiser insists.</p><p>In Retail Media, customer data is a <strong>First Party asset</strong> that belongs exclusively to the Retailer (you). File transfer is legally prohibited without a new specific opt-in (GDPR).</p><p>getinside operates as a <strong>Trusted Third Party</strong>: we route the advertiser&#39;s message to your audience, but the data never leaves your secure environment.</p><p>If an advertiser makes this request, direct them to our team: <a href="mailto:support@getinside.fr" target="_blank" rel="noreferrer">support@getinside.fr</a>.</p></details><details class="details custom-block"><summary>CSR and Printing Standards</summary><p>Our printing partners are certified <strong>Imprim&#39;vert</strong>, ISO 9001/14001, and use FSC paper. Manual assembly (e.g., samples) is carried out by <strong>Adapted Enterprises (EA)</strong> promoting the employment of disabled workers.</p></details><details class="details custom-block"><summary>Can I use the printing service for my own needs?</summary><p>Yes. As a central purchasing office, we offer all our members negotiated rates — for self-promotion or internal needs.</p></details><hr><h2 id="creation-tracking" tabindex="-1">Creation &amp; Tracking <a class="header-anchor" href="#creation-tracking" aria-label="Permalink to &quot;Creation &amp; Tracking&quot;">​</a></h2><details class="details custom-block"><summary>Can getinside create my visuals?</summary><p>Yes. Our <strong>Creative Studio</strong> can produce your flyers, emails, or banners for a flat fee of <strong>550€ HT</strong> per campaign.</p></details><details class="details custom-block"><summary>How to track sales (ROI)?</summary><p>getinside does not place a pixel on your site. Attribution relies on two levers:</p><ol><li><strong>Unique Promo Code:</strong> create a specific code (e.g., <code>THANKS20</code>).</li><li><strong>UTM Links:</strong> configure the URL of your QR Code with UTM parameters (e.g., <code>utm_source=parcel-insert</code>) to track traffic in Google Analytics.</li></ol></details>',29)])])}const h=t(r,[["render",o]]);export{m as __pageData,h as default};
